// Telegram-Nachricht formatieren
const input = $input.first().json;
const report = input.report_markdown || '';
const title = input.title || 'Research Report';
const qualityScore = input.quality_score ?? 0;
const confidenceScore = input.confidence_score ?? 0;
const sources = input.sources || [];
const claims = input.claims || [];
const runId = input.run_id || 'unknown';
const mode = input.mode || 'standard';

// Mode Badge
const modeBadges = {
  quick: '\ud83d\ude80 Quick',
  standard: '\ud83d\udcca Standard',
  deep: '\ud83d\udd2c Deep'
};
const modeBadge = modeBadges[mode] || modeBadges.standard;

// Executive Verdict: erste 2-3 Saetze aus dem Report
const plainReport = report.replace(/^#+\s.*$/gm, '').replace(/\n{2,}/g, '\n').trim();
const sentences = plainReport.split(/(?<=[.!?])\s+/).filter(s => s.length > 10);
const verdict = sentences.slice(0, 3).join(' ');

// Plattformen zaehlen
const platforms = new Set(sources.map(s => s.origin ? s.origin.split('+')[0] : 'unknown'));
const verifiedClaims = claims.filter(c => c.final_status === 'verified' || c.final_status === 'supported').length;

// Nachricht zusammenbauen
let msg = `*${title.replace(/[_*[\]()~`>#+\-=|{}.!]/g, '\\$&')}*\n`;
msg += `${modeBadge}\n\n`;
msg += `*Executive Verdict:*\n${verdict}\n\n`;
msg += `*Stats:*\n`;
msg += `\u2022 ${sources.length} sources from ${platforms.size} platforms\n`;
msg += `\u2022 ${claims.length} claims extracted, ${verifiedClaims} verified\n`;
msg += `\u2022 Quality: ${(qualityScore * 100).toFixed(0)}% | Confidence: ${(confidenceScore * 100).toFixed(0)}%\n`;
msg += `\n\u2014 Run: \`${runId}\``;

// Telegram 4096 char Limit
if (msg.length > 4096) {
  msg = msg.slice(0, 4090) + '\n...';
}

return [{
  json: {
    formatted_message: msg,
    run_id: runId,
    title,
    report_markdown: report,
    quality_score: qualityScore,
    confidence_score: confidenceScore,
    sources,
    claims,
    mode
  }
}];

