// UPSERT SQL fuer alle Sources und Claims generieren
const input = $('Prepare Telegram Message').first().json;
const surrealResp = $input.first().json;

// Report-ID aus SurrealDB Response extrahieren
const results = surrealResp.result || surrealResp[0]?.result || [];
const reportRecord = Array.isArray(results) ? results[0] : results;
const reportId = reportRecord?.id || `research_report:${input.run_id}`;

const sources = input.sources || [];
const claims = input.claims || [];
const runId = input.run_id;

const sqlStatements = [];

// Source UPSERTs
for (const source of sources) {
  const urlEsc = (source.url || '').replace(/'/g, "''");
  const titleEsc = (source.title || '').replace(/'/g, "''");
  const snippetEsc = (source.snippet || '').slice(0, 1000).replace(/'/g, "''");
  const origin = source.origin || 'unknown';
  const tier = source.tier || 'T3';
  const sourceType = source.source_type || 'web';
  const relevance = source.relevance_score || 0.5;

  // UPSERT source_registry: bei Konflikt auf url -> update
  sqlStatements.push(
    `UPSERT source_registry SET url = '${urlEsc}', title = '${titleEsc}', source_type = '${sourceType}', trust_level = 'T3', reputation = IF reputation THEN reputation ELSE 0.5 END, run_count = IF run_count THEN run_count + 1 ELSE 1 END, last_seen = time::now(), created_at = IF created_at THEN created_at ELSE time::now() END WHERE url = '${urlEsc}'`
  );

  // used_source Edge
  sqlStatements.push(
    `INSERT INTO used_source { in: ${reportId}, out: source_registry:[\'${urlEsc}\'], relevance_score: ${relevance}, tier: '${tier}', origin: '${origin}', snippet: '${snippetEsc}' }`
  );
}

// Claim INSERTs
for (let i = 0; i < claims.length; i++) {
  const claim = claims[i];
  const textEsc = (claim.text || '').replace(/'/g, "''");
  const srcUrlEsc = (claim.source_url || '').replace(/'/g, "''");
  const status = claim.final_status || 'pending';
  const confidence = claim.confidence || 0.0;

  sqlStatements.push(
    `INSERT INTO research_claim { run_id: '${runId}', report: ${reportId}, text: '${textEsc}', source_url: '${srcUrlEsc}', source_title: '${(claim.source_title || '').replace(/'/g, "''")}', confidence: ${confidence}, cove_status: '${claim.cove_status || 'unchecked'}', final_status: '${status}', created_at: time::now() }`
  );
}

// Research Run als completed markieren
sqlStatements.push(
  `UPDATE research_run SET status = 'completed', report_id = ${reportId}, completed_at = time::now() WHERE run_id = '${runId}'`
);

const batchSql = sqlStatements.join(';\n');

return [{
  json: {
    batch_sql: batchSql,
    report_id: reportId,
    run_id: runId,
    source_count: sources.length,
    claim_count: claims.length
  }
}];

// Feedback-Buttons fuer Telegram vorbereiten
const input = $('Prepare Source Upserts').first().json;
const runId = input.run_id;
const reportId = input.report_id;

const inlineKeyboard = {
  inline_keyboard: [
    [
      { text: '\ud83d\udc4d', callback_data: `rate_up_${runId}` },
      { text: '\ud83d\udc4e', callback_data: `rate_down_${runId}` }
    ]
  ]
};

return [{
  json: {
    reply_markup: inlineKeyboard,
    run_id: runId,
    report_id: reportId,
    telegram_message_id: $('Telegram \u2014 Send Report').first().json.result?.message_id || null
  }
}];
